define <2 x i1> @sext_zext_ne(<2 x i8> %x, <2 x i8> %y) {
  %a = sext <2 x i8> %x to <2 x i32>
  %b = zext <2 x i8> %y to <2 x i32>
  %c = icmp ne <2 x i32> %a, %b
  ret <2 x i1> %c
}

